text:
            LOGGER.info(
                "Reusing previously assigned code for %s -> %s", email, existing_code
            )
            assignments.append((email, existing_code))
            continue

        if code_index >= len(available_codes):
            raise RuntimeError(
                "Ran out of beta codes. Add more codes to beta_codes.csv before rerunning."
            )

        next_code = available_codes[code_index]
        LOGGER.info("Assigning new code for %s -> %s", email, next_code)
        assignments.append((email, next_code))
        used_codes.add(next_code)
        code_index += 1

    return assignments


